// Manual Demo Mode Router - Routes messages based on demo mode toggle
// UPDATED: Command-based routing (highest priority)
// DEFAULT: All messages → Rensto Support
// DEMO MODE: Specific phone numbers → Their respective agents

// Get static data from THIS workflow (router workflow)
let staticData = {};
try {
  staticData = this.getWorkflowStaticData('global');
} catch (e) {
  staticData = {};
}

// PRIORITY 1: Check for command override (highest priority)
// Commands like @tax4us, @meatpoint override everything
const agentOverride = $json.agent_override || null;
if (agentOverride) {
  console.log(`[Router] 🎯 Using command override: ${agentOverride}`);

  // Workflow IDs
  const agentWorkflows = {
    'liza-ai': '86WHKNpj09tV9j1d', // Liza AI - Kitchen Design Assistant (webhook)
    'rensto-support': 'eQSCUFw91oXLxtvn', // Rensto Support Agent
    'meatpoint-agent': 'wctBX3HGve9jhdPG', // MeatPoint Agent
    'tax4us-ai': 'afuwFRbipP3bqNZz', // Tax4US Agent
  };

  const workflowId = agentWorkflows[agentOverride] || agentWorkflows['rensto-support'];

  return {
    json: {
      sender_phone: $json.sender_phone || '',
      agent_id: agentOverride,
      workflow_id: workflowId,
      agent_name: agentOverride === 'liza-ai' ? 'Liza AI' : (agentOverride === 'rensto-support' ? 'Rensto Support' : (agentOverride === 'tax4us-ai' ? 'Tax4US Agent' : 'MeatPoint Agent')),
      message_text: $json.message_text || '', // Already has command removed by Parse Command node
      message_type: $json.message_type || 'text',
      voice_url: $json.voice_url || '',
      original_payload: $json.original_payload || {},
      demo_mode_active: false,
      command_override: true
    }
  };
}

// PRIORITY 2: Demo mode mappings (phone number → agent)
// Format: { "phone@c.us": "agent-id" }
// Example: { "4695885133@c.us": "tax4us-ai" }
// These are updated by the Demo Mode Toggle Webhook workflow
const demoModeMappings = staticData.demoModeMappings || {};

// PRIORITY 3: Hard-coded permanent mappings (if any)
const permanentMappings = {
  // Tax4US Agent - Testing numbers
  '4695885133@c.us': 'tax4us-ai', // Shai (Tax4US testing)
  '14695885133@c.us': 'tax4us-ai', // Shai with country code (Tax4US testing)
  // Tax4US Agent - Ben Ginati (Owner)
  '972546339096@c.us': 'tax4us-ai', // Ben Ginati - Israel (+972 54-633-9096)
  '14699695584@c.us': 'tax4us-ai', // Ben Ginati - US (+1 469-969-5584)
  '4699695584@c.us': 'tax4us-ai', // Ben Ginati - US without country code
  // MeatPoint Agent - Only these numbers route to MeatPoint
  '19544043156@c.us': 'meatpoint-agent', // Yehuda Alali (MeatPoint)
  // Add more permanent mappings here if needed
  // '972528353052@c.us': 'liza-ai', // Example
};

const senderPhone = $json.sender_phone || '';

// Determine agent based on priority:
// 1. Command override (already handled above)
// 2. Check demo mode mappings
// 3. Check permanent mappings
// 4. Default to Rensto Support
let agentId;

if (demoModeMappings[senderPhone]) {
  // Demo mode active for this phone number
  agentId = demoModeMappings[senderPhone];
  console.log(`[Router] 🎯 Demo mode: ${senderPhone} → ${agentId}`);
} else if (permanentMappings[senderPhone]) {
  // Permanent mapping
  agentId = permanentMappings[senderPhone];
  console.log(`[Router] 📌 Permanent: ${senderPhone} → ${agentId}`);
} else {
  // Default: Route all messages to Rensto Support
  agentId = 'rensto-support';
  console.log(`[Router] 🔄 Default: ${senderPhone} → Rensto Support`);
}

// Workflow IDs
const agentWorkflows = {
  'liza-ai': '86WHKNpj09tV9j1d', // Liza AI - Kitchen Design Assistant (webhook)
  'rensto-support': 'eQSCUFw91oXLxtvn', // Rensto Support Agent
  'meatpoint-agent': 'wctBX3HGve9jhdPG', // MeatPoint Agent
  'tax4us-ai': 'afuwFRbipP3bqNZz', // Tax4US Agent
};

const workflowId = agentWorkflows[agentId] || agentWorkflows['rensto-support'];

return {
  json: {
    sender_phone: senderPhone,
    agent_id: agentId,
    workflow_id: workflowId,
    agent_name: agentId === 'liza-ai' ? 'Liza AI' : (agentId === 'rensto-support' ? 'Rensto Support' : (agentId === 'tax4us-ai' ? 'Tax4US Agent' : 'MeatPoint Agent')),
    message_text: $json.message_text || '',
    message_type: $json.message_type || 'text',
    voice_url: $json.voice_url || '',
    original_payload: $json.original_payload || {},
    demo_mode_active: !!demoModeMappings[senderPhone],
    command_override: false
  }
};

// Process WAHA Trigger output - access data from output[1]
// WAHA Trigger outputs message events in output[1], connection is from output[0] (empty)
// Try to access WAHA Trigger's output[1] data via $node reference
const items = $input.all();
const results = [];

console.log('[Process WAHA] Received items from input:', items.length);

// Try to get data from WAHA Trigger node's output[1]
try {
  // Access previous node's data - WAHA Trigger puts data in output[1]
  const wahaNode = $node['WAHA Trigger'];
  if (wahaNode && wahaNode.json) {
    const event = wahaNode.json.event || '';
    const payload = wahaNode.json.payload || {};

    console.log('[Process WAHA] Got data from $node, event:', event);

    if (event === 'message') {
      results.push({
        json: {
          id: wahaNode.json.id,
          timestamp: wahaNode.json.timestamp,
          event: event,
          session: wahaNode.json.session || 'default',
          payload: payload,
          me: wahaNode.json.me || {},
          engine: wahaNode.json.engine || '',
          environment: wahaNode.json.environment || {}
        }
      });
    }
  }
} catch (e) {
  console.log('[Process WAHA] $node access failed:', e.message);
}

// Also process items from input (in case connection works)
for (const item of items) {
  const event = item.json?.event || '';
  const payload = item.json?.payload || item.json || {};

  if (event === 'message' && !results.find(r => r.json.id === item.json?.id)) {
    results.push({
      json: {
        id: item.json.id,
        timestamp: item.json.timestamp,
        event: event,
        session: item.json.session || 'default',
        payload: payload,
        me: item.json.me || {},
        engine: item.json.engine || '',
        environment: item.json.environment || {}
      }
    });
  }
}

console.log('[Process WAHA] Returning', results.length, 'message events');
return results;

// Parse Command from Message - Smart routing via @agent-name commands
// Pattern: @agent-name message
// Example: @tax4us Hi, can you help me?

const messageText = $json.message_text || '';
const senderPhone = $json.sender_phone || '';

// Check for command pattern: @agent-name message
// Supports: @tax4us, @tax4, @meatpoint, @meat, @rensto, @support, @liza
const commandPattern = /^@(\w+)(?:\s+(.+))?$/;
const match = messageText.trim().match(commandPattern);

let agentOverride = null;
let actualMessage = messageText;

if (match) {
  const command = match[1].toLowerCase();
  actualMessage = match[2] || ''; // Message without command (or empty if just command)

  // Map commands to agent IDs
  const commandMap = {
    'tax4us': 'tax4us-ai',
    'tax4': 'tax4us-ai',
    'meatpoint': 'meatpoint-agent',
    'meat': 'meatpoint-agent',
    'rensto': 'rensto-support',
    'support': 'rensto-support',
    'liza': 'liza-ai',
    'default': 'rensto-support'
  };

  agentOverride = commandMap[command] || null;

  if (agentOverride) {
    console.log(`[Router] 🎯 Command detected: @${command} → ${agentOverride}`);
    console.log(`[Router] Message after command removal: "${actualMessage}"`);
  } else {
    console.log(`[Router] ⚠️ Unknown command: @${command} - using normal routing`);
    // If unknown command, treat as normal message (no override)
    actualMessage = messageText; // Keep original message
  }
}

return {
  json: {
    ...$json,
    message_text: actualMessage, // Message without command (or original if no command)
    original_message_text: messageText, // Original with command preserved
    agent_override: agentOverride, // Agent ID if command found, null otherwise
    has_command: !!agentOverride
  }
};

// Universal Smart Message Router - Handle 'message', 'message.any', AND 'engine.event' events
// UPDATED: Handle data from router (Execute Workflow) - checks original_payload first
// ADDED: Deduplication - skip direct webhook if already processed by router
// CRITICAL: Store 'this' reference at top level to preserve context
const self = this;
const items = $input.all();
const results = [];

console.log('[Router] ===== STARTING ROUTER (V2 ROBUST) =====');
console.log('[Router] Input items count:', items.length);

// Use 'global' scope so other nodes can access this data
let staticData;
try {
  staticData = self.getWorkflowStaticData('global');
} catch (error) {
  staticData = {};
}

// Use arrays instead of Sets to avoid serialization issues
staticData.processedMessageIds = staticData.processedMessageIds || [];
staticData.processedMessageTimestamps = staticData.processedMessageTimestamps || {};
staticData.rateLimitTracker = staticData.rateLimitTracker || {};

// Deduplication: Check if message was already processed
if (!staticData.processedMessages) {
  staticData.processedMessages = {};
}

const now = Date.now();

// Helper: Recursively find text content in object
const findTextContent = (obj, depth = 0) => {
  if (!obj || typeof obj !== 'object' || depth > 5) return null;

  // Direct checks
  if (obj.caption) return obj.caption;
  if (obj.conversation) return obj.conversation;
  if (obj.text && typeof obj.text === 'string') return obj.text;

  // Recursive search
  for (const key in obj) {
    if (key === 'contextInfo' || key === 'quotedMessage') continue; // Skip quoted messages
    const res = findTextContent(obj[key], depth + 1);
    if (res) return res;
  }
  return null;
};

// STRICT check-and-mark function
const tryMarkAsProcessed = (keys) => {
  if (!Array.isArray(keys) || keys.length === 0) return false;
  const processed = staticData.processedMessageIds;
  const timestamps = staticData.processedMessageTimestamps;
  const now = Date.now();

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    if (key && processed.includes(key)) {
      console.log('[Router] ⏭️ Skipping duplicate message:', key);
      return false;
    }
  }

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    if (key && !processed.includes(key)) {
      processed.push(key);
      timestamps[key] = now;
    }
  }

  // Cleanup
  if (processed.length > 1000) {
    const oldKeys = processed.slice(0, processed.length - 1000);
    processed.splice(0, processed.length - 1000);
    for (let i = 0; i < oldKeys.length; i++) {
      delete timestamps[oldKeys[i]];
    }
  }
  return true;
};

const checkRateLimit = (userId, maxMessages, windowMs) => {
  maxMessages = maxMessages || 10;
  windowMs = windowMs || 60000;
  const now = Date.now();
  const tracker = staticData.rateLimitTracker;

  if (!tracker[userId]) tracker[userId] = [];

  const recentMessages = tracker[userId].filter(t => now - t < windowMs);
  tracker[userId] = recentMessages;

  if (recentMessages.length >= maxMessages) return false;

  tracker[userId].push(now);
  return true;
};

// Helper: Extract message data
// UPDATED: Handle data from router (Execute Workflow) - checks original_payload first
// ADDED: Deduplication check for direct webhooks
const extractMessageData = (item) => {
  const msg = item.json || {};

  // CRITICAL: Handle data from router (Execute Workflow) - router passes original_payload
  // Also handle direct WAHA trigger format (payload) and webhook format
  let payload = msg.original_payload || msg.payload || {};
  const eventType = msg.event || 'message';

  // CRITICAL: Handle direct webhook format (body.payload)
  if (msg.body?.payload && !msg.original_payload) {
    // This is a direct webhook (not from router)
    payload = msg.body.payload;
    const messageId = payload.id || '';
    const timestamp = payload.timestamp || 0;
    const processedKey = `${messageId}_${timestamp}`;

    // Check if router already processed this message (within last 10 seconds)
    if (staticData.processedMessages[processedKey]) {
      const processedTime = staticData.processedMessages[processedKey];
      const timeDiff = now - processedTime;

      if (timeDiff < 10000) { // 10 seconds
        console.log(`[Router] ⏭️ Skipping duplicate direct webhook (processed ${timeDiff}ms ago):`, messageId);
        return null; // Skip - already processed by router
      }
    }

    // Mark as processed
    staticData.processedMessages[processedKey] = now;
    console.log(`[Router] ✅ Processing direct webhook message:`, messageId);
  } else if (msg.original_payload) {
    // This is from router (Execute Workflow) - mark as processed
    const messageId = payload.id || '';
    const timestamp = payload.timestamp || 0;
    const processedKey = `${messageId}_${timestamp}`;
    staticData.processedMessages[processedKey] = now;
    console.log(`[Router] ✅ Processing router message:`, messageId);
  }

  // Cleanup old entries (older than 60 seconds)
  for (const key in staticData.processedMessages) {
    if (now - staticData.processedMessages[key] > 60000) {
      delete staticData.processedMessages[key];
    }
  }

  // CRITICAL: Skip non-message events (session.status, etc.)
  if (eventType !== 'message' && eventType !== 'message.any' && eventType !== 'engine.event') {
    console.log('[Router] ⏭️ Skipping non-message event:', eventType);
    return null;
  }

  if (eventType === 'message' || eventType === 'message.any') {
    return {
      payload: payload,
      _data: payload._data || {},
      fromMe: payload.fromMe || false
    };
  }

  if (eventType === 'engine.event') {
    let messageData;
    if (payload.event === 'messages.upsert') {
      messageData = payload.data?.messages?.[0];
    } else if (payload.event === 'chats.update') {
      messageData = payload.data?.[0]?.messages?.[0]?.message; // Structure varies
    }

    if (messageData) {
      const key = messageData.key || {};
      const message = messageData.message || {};

      // ROBUST: Use recursive finder
      const body = findTextContent(message) || '';

      return {
        payload: {
          id: key.id || '',
          from: key.remoteJid || '',
          fromMe: key.fromMe || false,
          timestamp: messageData.messageTimestamp || Date.now(),
          body: body,
          hasMedia: !!(message.imageMessage || message.videoMessage || message.documentMessage || message.audioMessage),
          media: message.imageMessage ? { url: message.imageMessage.url, mimetype: message.imageMessage.mimetype } : null,
          _data: { key, messageTimestamp: messageData.messageTimestamp, message }
        },
        _data: { key, messageTimestamp: messageData.messageTimestamp, message },
        fromMe: key.fromMe || false
      };
    }
  }
  return null;
};

for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const item = items[itemIndex];
  const messageData = extractMessageData(item);
  if (!messageData) continue;

  const payload = messageData.payload || {};
  const _data = messageData._data || {};

  if (messageData.fromMe === true) continue;

  const _dataKey = _data.key || {};
  const actualMessageId = _dataKey.id || payload.id || '';
  const compositeId = payload.id || '';
  const remoteJid = payload.from || _dataKey.remoteJid || '';
  const userId = remoteJid ? String(remoteJid).replace('@s.whatsapp.net', '@c.us') : '';
  const timestamp = payload.timestamp || _data.messageTimestamp || Date.now();

  const dedupKeys = [actualMessageId, compositeId].filter(k => k);

  try { self.setWorkflowStaticData('global', staticData); } catch (e) {}
  if (!tryMarkAsProcessed(dedupKeys)) continue;
  try { self.setWorkflowStaticData('global', staticData); } catch (e) {}

  if (userId && !checkRateLimit(userId)) continue;

  let messageType = 'text';

  // ROBUST: Use recursive finder for text content
  let textContent = payload.body || '';
  if (!textContent && _data.message) {
    textContent = findTextContent(_data.message) || '';
  }

  let mediaUrl = '';
  let mediaInfo = {};

  const _dataMessage = _data.message || {};
  const audioMsg = _dataMessage.audioMessage || null;

  if (payload.hasMedia === true || _dataMessage.imageMessage || _dataMessage.videoMessage || _dataMessage.documentMessage || _dataMessage.audioMessage) {
    if (audioMsg || _dataMessage.audioMessage) {
      const audio = audioMsg || _dataMessage.audioMessage;
      messageType = 'voice';
      mediaUrl = (payload.media && payload.media.url) || audio.url || '';
      mediaInfo = { isPTT: audio.ptt === true, mimetype: audio.mimetype || 'audio/ogg' };
    } else if (_dataMessage.imageMessage) {
      messageType = 'image';
      mediaUrl = _dataMessage.imageMessage.url || '';
      mediaInfo = { mimetype: _dataMessage.imageMessage.mimetype || 'image/jpeg' };
    } else if (_dataMessage.videoMessage) {
      messageType = 'video';
      mediaUrl = _dataMessage.videoMessage.url || '';
      mediaInfo = { mimetype: _dataMessage.videoMessage.mimetype || 'video/mp4' };
    } else if (_dataMessage.documentMessage) {
      messageType = 'document';
      mediaUrl = _dataMessage.documentMessage.url || '';
      mediaInfo = { mimetype: _dataMessage.documentMessage.mimetype || 'application/pdf' };
    }
  } else if (_dataMessage.ptt === true) {
    messageType = 'voice';
    if (audioMsg && audioMsg.url) mediaUrl = audioMsg.url;
    mediaInfo = { isPTT: true, mimetype: audioMsg ? audioMsg.mimetype : 'audio/ogg' };
  }

  // Fix localhost URLs
  if (mediaUrl && mediaUrl.includes('localhost')) {
    mediaUrl = mediaUrl.replace('localhost', '173.254.201.134');
  }

  const messageId = actualMessageId || compositeId;

  staticData.lastMessageMetadata = {
    userId: userId,
    messageId: messageId,
    sessionId: userId,
    requiresVoiceResponse: messageType === 'voice',
    source: 'waha',
    store_name: 'fileSearchStores/rensto-knowledge-base-ndf9fmymwb2p'
  };

  try { self.setWorkflowStaticData('global', staticData); } catch (e) {}

  console.log('[Router] ✅ Processed:', messageType, 'ID:', messageId, 'Text:', textContent.substring(0, 50));

  results.push({
    json: {
      messageId: messageId,
      messageType: messageType,
      source: 'waha',
      userId: userId,
      timestamp: timestamp,
      textContent: textContent,
      mediaUrl: mediaUrl,
      mediaInfo: mediaInfo,
      originalPayload: payload,
      requiresVoiceResponse: messageType === 'voice',
      sessionId: userId
    }
  });
}

return results;

// Process Media Context - FIXED: Robust fallback for failed analysis
const inputData = $json || {};

let routerData = {};
try {
  routerData = $node['Merge Image Analysis'].json || {};
} catch (e) {
  try { routerData = $node['Message Type Router'].json || {}; } catch (e2) { routerData = {}; }
}

const messageType = inputData.messageType || routerData.messageType || 'text';
const originalTextContent = String(routerData.textContent || routerData.caption || inputData.textContent || inputData.caption || '').trim();

const geminiFields = ['guardrailsInput', 'output', 'text', 'response', 'analysis', 'extractedText'];
const extractField = (data, fields) => {
  for (const field of fields) {
    if (data[field]) return String(data[field]).trim();
  }
  return '';
};

let processedText = '';
let userQuestion = '';
let imageAnalysisText = '';
const geminiOutput = extractField(inputData, geminiFields);

if (messageType === 'text') {
  processedText = originalTextContent || inputData.body || inputData.text || inputData.processedText || '';
  userQuestion = processedText;
} else {
  userQuestion = originalTextContent || inputData.body || '';

  if (geminiOutput) {
    imageAnalysisText = geminiOutput;
    processedText = geminiOutput;
  } else if (originalTextContent) {
    processedText = originalTextContent;
    userQuestion = originalTextContent;
  } else {
    // Default question if empty
    processedText = `I received your ${messageType}. How can I help you with it?`;
    userQuestion = `Analyze this ${messageType}`;
  }
}

processedText = String(processedText || '').trim();
userQuestion = String(userQuestion || '').trim();
imageAnalysisText = String(imageAnalysisText || '').trim();

// CRITICAL FIX: If we are using the default "Analyze this..." question BUT have no analysis,
// we must change the question to avoid AI hallucinating "message didn't come through".
if (userQuestion.includes('Analyze this') && !imageAnalysisText && !originalTextContent) {
  console.log('[Process Media] ⚠️ Analysis missing for default prompt - switching to fallback prompt');
  userQuestion = "I sent an image but the system could not analyze it. Please ask me to describe what is in the image.";
  processedText = userQuestion;
}

if (!processedText && messageType !== 'text') {
  processedText = `I received your ${messageType} but need more context. Could you please describe what you need help with?`;
  userQuestion = "I sent an image but the system could not analyze it. Please ask me to describe what is in the image.";
}

console.log('[Process Media] Final User Question:', userQuestion);
console.log('[Process Media] Image Analysis Length:', imageAnalysisText.length);

return {
  json: {
    userId: routerData.userId || inputData.userId,
    messageId: routerData.messageId || inputData.messageId,
    sessionId: routerData.sessionId || inputData.sessionId,
    timestamp: routerData.timestamp || inputData.timestamp,
    source: routerData.source || inputData.source || 'waha',
    messageType: messageType,
    mediaUrl: routerData.mediaUrl || inputData.mediaUrl,
    mediaInfo: routerData.mediaInfo || inputData.mediaInfo,
    originalPayload: routerData.originalPayload || inputData.originalPayload,
    requiresVoiceResponse: routerData.requiresVoiceResponse || inputData.requiresVoiceResponse,
    originalQuestion: userQuestion,
    originalCaption: originalTextContent,
    geminiAnalysis: imageAnalysisText || null,
    imageAnalysis: imageAnalysisText || null,
    processedText: processedText,
    textContent: processedText,
    text: processedText,
    body: processedText,
    question: userQuestion || processedText
  }
};

// ULTIMATE BULLETPROOF Prepare AI Input - FIXED: Set hasImageAnalysis flag in static data
console.log('\n=== PREPARE AI INPUT - ULTIMATE DEBUG ===');

// Get ALL inputs
const allInputs = $input.all();
console.log('Total inputs received:', allInputs.length);

if (!allInputs || allInputs.length === 0) {
  throw new Error('No input data received! Check upstream nodes.');
}

// Get static data FIRST (most reliable source)
let staticData = {};
try {
  staticData = this.getWorkflowStaticData('global');
  console.log('Static data keys:', Object.keys(staticData).join(', '));
  if (staticData.lastMessageMetadata) {
    console.log('Static metadata userId:', staticData.lastMessageMetadata.userId);
  }
} catch (error) {
  console.log('Static data error:', error.message);
  staticData = {};
}

// AGGRESSIVE userId EXTRACTION - Try EVERY possible source
let userId = '';
let extractionMethod = '';

// PRIORITY 1: Static data (most reliable - set by Smart Message Router)
if (staticData.lastMessageMetadata && staticData.lastMessageMetadata.userId) {
  userId = String(staticData.lastMessageMetadata.userId);
  extractionMethod = 'static data (lastMessageMetadata)';
  console.log('✅ Found userId in static data:', userId);
}

// PRIORITY 2: Try upstream nodes using $node (if available)
if (!userId) {
  const upstreamNodeNames = ['Smart Message Router', 'Message Type Router', 'Process Media Context', 'Download Voice', 'Transcribe Voice'];
  for (let i = 0; i < upstreamNodeNames.length; i++) {
    const nodeName = upstreamNodeNames[i];
    try {
      const nodeData = $node[nodeName];
      if (nodeData && nodeData.json) {
        const nodeUserId = nodeData.json.userId || nodeData.json.from || nodeData.json.designer_phone || '';
        if (nodeUserId) {
          userId = String(nodeUserId);
          extractionMethod = '$node[' + nodeName + ']';
          console.log('✅ Found userId in upstream node', nodeName, ':', userId);
          break;
        }

        // Check nested payload
        if (!userId && nodeData.json.payload) {
          const payloadUserId = nodeData.json.payload.userId || nodeData.json.payload.from || '';
          if (payloadUserId) {
            userId = String(payloadUserId);
            extractionMethod = '$node[' + nodeName + '].payload';
            console.log('✅ Found userId in upstream node', nodeName, 'payload:', userId);
            break;
          }
        }

        // Check originalPayload
        if (!userId && nodeData.json.originalPayload) {
          const opUserId = nodeData.json.originalPayload.userId || nodeData.json.originalPayload.from || '';
          if (opUserId) {
            userId = String(opUserId);
            extractionMethod = '$node[' + nodeName + '].originalPayload';
            console.log('✅ Found userId in upstream node', nodeName, 'originalPayload:', userId);
            break;
          }
        }
      }
    } catch (error) {
      // Node might not exist or not accessible - continue
      console.log('Could not access node', nodeName, ':', error.message);
    }
  }
}

// PRIORITY 3: Check ALL input items
if (!userId) {
  for (let i = 0; i < allInputs.length; i++) {
