// Smart Message Router - Filter protocol messages and route by type
// ADDED: Language preference detection and storage
// UPDATED: Handle data from router (Execute Workflow) - checks original_payload first
// ADDED: Deduplication - skip direct webhook if already processed by router
const items = $input.all();
const results = [];

// Get static data for deduplication
let staticData = {};
try {
  staticData = this.getWorkflowStaticData('global');
} catch (e) {
  staticData = {};
}

if (!staticData.processedMessages) {
  staticData.processedMessages = {};
}

const now = Date.now();

for (const item of items) {
  // Handle data from router (Execute Workflow) - router passes original_payload
  // Also handle direct WAHA trigger format (payload) and webhook format
  let payload = item.json.original_payload || item.json.payload || item.json || {};
  const event = item.json.event || 'message';

  // CRITICAL: Handle direct webhook format (body.payload)
  if (item.json.body?.payload && !item.json.original_payload) {
    // This is a direct webhook (not from router)
    payload = item.json.body.payload;
    const messageId = payload.id || '';
    const timestamp = payload.timestamp || 0;
    const processedKey = `${messageId}_${timestamp}`;

    // Check if router already processed this message (within last 10 seconds)
    if (staticData.processedMessages[processedKey]) {
      const processedTime = staticData.processedMessages[processedKey];
      const timeDiff = now - processedTime;

      if (timeDiff < 10000) { // 10 seconds
        console.log(`[Router] ⏭️ Skipping duplicate direct webhook (processed ${timeDiff}ms ago):`, messageId);
        continue; // Skip - already processed by router
      }
    }

    // Mark as processed
    staticData.processedMessages[processedKey] = now;
    console.log(`[Router] ✅ Processing direct webhook message:`, messageId);
  } else if (item.json.original_payload) {
    // This is from router (Execute Workflow) - mark as processed
    const messageId = payload.id || '';
    const timestamp = payload.timestamp || 0;
    const processedKey = `${messageId}_${timestamp}`;
    staticData.processedMessages[processedKey] = now;
    console.log(`[Router] ✅ Processing router message:`, messageId);
  }

  // Cleanup old entries (older than 60 seconds)
  for (const key in staticData.processedMessages) {
    if (now - staticData.processedMessages[key] > 60000) {
      delete staticData.processedMessages[key];
    }
  }

  // CRITICAL: Skip non-message events (session.status, etc.)
  if (event !== 'message') {
    console.log('[Router] ⏭️ Skipping non-message event:', event);
    continue;
  }

  // CRITICAL: Skip protocol/system messages (no body, protocolMessage in _data)
  const hasProtocolMessage = payload._data?.message?.protocolMessage;
  const hasBody = payload.body !== null && payload.body !== undefined && String(payload.body).trim() !== '';
  const hasMedia = Boolean(payload.hasMedia && payload.media);

  // FIXED: Allow media messages even if body is null
  if (hasProtocolMessage || (!hasBody && !hasMedia)) {
    console.log('[Router] ⏭️ Skipping protocol/system message (no body and no media)');
    continue;
  }

  const userId = payload.from || payload.userId || '';
  const messageId = payload.id || payload.messageId || '';
  const timestamp = payload.timestamp || Date.now();
  const body = String(payload.body || '').trim();
  // NOTE: hasMedia is already declared above, don't redeclare it here

  // Detect language preference from message
  let detectedLanguage = 'english';
  const bodyLower = body.toLowerCase();
  const hebrewPattern = /[\u0590-\u05FF]/;
  if (hebrewPattern.test(body)) {
    detectedLanguage = 'hebrew';
  } else if (bodyLower.includes('hebrew') || bodyLower.includes('עברית')) {
    detectedLanguage = 'hebrew';
  } else if (bodyLower.includes('english') || bodyLower.includes('אנגלית')) {
    detectedLanguage = 'english';
  }

  let messageType = 'text';
  let textContent = body;
  let mediaUrl = '';
  let mediaInfo = {};

  if (hasMedia && payload.media) {
    mediaUrl = payload.media.url || '';
    const mimetype = payload.media.mimetype || '';

    if (mimetype.startsWith('audio/') || mimetype === 'audio/ogg; codecs=opus') {
      messageType = 'voice';
    } else if (mimetype.startsWith('image/')) {
      messageType = 'image';
      textContent = payload.caption || body || '';
    } else if (mimetype.startsWith('video/')) {
      messageType = 'video';
      textContent = payload.caption || body || '';
    } else if (mimetype.includes('pdf') || mimetype.includes('document')) {
      messageType = 'document';
      textContent = payload.caption || body || '';
    }

    mediaInfo = {
      mimetype: mimetype,
      filename: payload.media.filename || '',
      size: payload.media.size || 0
    };
  }

  // Store language preference if detected or already set
  if (!staticData.userLanguagePreferences) {
    staticData.userLanguagePreferences = {};
  }
  if (detectedLanguage !== 'english' || staticData.userLanguagePreferences[userId]) {
    staticData.userLanguagePreferences[userId] = detectedLanguage;
  }

  staticData.lastMessageMetadata = {
    userId: userId,
    messageId: messageId,
    requiresVoiceResponse: messageType === 'voice',
    source: 'waha',
    store_name: 'fileSearchStores/tax4usknowledgebasendf9fmym-bo4pew7b5a3x',
    detectedLanguage: detectedLanguage,
    preferredLanguage: staticData.userLanguagePreferences[userId] || 'english'
  };

  try { this.setWorkflowStaticData('global', staticData); } catch (e) {}

  console.log('[Router] ✅ Processed:', messageType, 'ID:', messageId, 'Text:', textContent.substring(0, 50), 'Language:', detectedLanguage);

  results.push({
    json: {
      messageId: messageId,
      messageType: messageType,
      source: 'waha',
      userId: userId,
      timestamp: timestamp,
      textContent: textContent,
      mediaUrl: mediaUrl,
      mediaInfo: mediaInfo,
      originalPayload: payload,
      requiresVoiceResponse: messageType === 'voice',
      sessionId: userId,
      detectedLanguage: detectedLanguage,
      preferredLanguage: staticData.userLanguagePreferences[userId] || 'english'
    }
  });
}

return results;

