// Extract response text from agent output
// Handle both plain text and JSON responses
const output = $input.item.json.output || '';

let responseText = '';

// Try to parse as JSON if it's a string
if (typeof output === 'string') {
  try {
    const parsed = JSON.parse(output);
    // If it's a JSON object with answer/text field, extract it
    responseText = parsed.answer || parsed.text || parsed.output || output;
  } catch (e) {
    // Not JSON, use as-is
    responseText = output;
  }
} else if (typeof output === 'object' && output !== null) {
  // If it's already an object, extract answer/text
  responseText = output.answer || output.text || output.output || String(output);
} else {
  responseText = String(output || '');
}

// Clean up tool markers - handle nested brackets properly
// Find [Used tools: and remove everything until the matching closing bracket
let cleaned = responseText;

// Remove [Used tools: ... ] blocks (handles nested brackets)
const usedToolsStart = cleaned.indexOf('[Used tools:');
if (usedToolsStart !== -1) {
  // Find the matching closing bracket by counting brackets
  let bracketCount = 0;
  let i = usedToolsStart;
  let endPos = -1;

  for (; i < cleaned.length; i++) {
    if (cleaned[i] === '[') bracketCount++;
    if (cleaned[i] === ']') {
      bracketCount--;
      if (bracketCount === 0) {
        endPos = i;
        break;
      }
    }
  }

  if (endPos !== -1) {
    // Remove the [Used tools: ... ] block
    cleaned = cleaned.substring(0, usedToolsStart) + cleaned.substring(endPos + 1);
  } else {
    // Fallback: remove from [Used tools: to end if no matching bracket found
    cleaned = cleaned.substring(0, usedToolsStart);
  }
}

// Also remove [Tool: ... ] blocks (simpler pattern)
cleaned = cleaned.replace(/\[Tool:[^\]]*\]/g, '');

// Clean up any leftover brackets or whitespace
cleaned = cleaned.replace(/^\s*[\]\[]+\s*/g, '').trim();

// Get designer phone from earlier in the flow
const designerPhone = $('Prepare Question Text').item.json.designer_phone || '';

return {
  json: {
    response_text: cleaned,
    designer_phone: designerPhone
  }
};

// Process all items from all input connections
// For voice messages: we receive 2 items - one empty from text path, one with transcription
// We need to prioritize the transcription item and ignore the empty one
const allItems = $input.all();
const results = [];

// Separate items by type
const textItems = [];
const voiceItems = [];

for (const inputItem of allItems) {
  const item = inputItem.json;
  const messageType = item.message_type || 'text';
  const hasTranscription = item.text && item.text.trim().length > 0;

  if (messageType === 'text') {
    textItems.push(inputItem);
  } else if (messageType === 'ptt') {
    voiceItems.push({ item: inputItem, hasTranscription });
  }
}

// Process text messages
for (const inputItem of textItems) {
  const item = inputItem.json;
  const questionText = (item.message_text || '').trim();

  if (questionText && questionText.length > 0) {
    results.push({
      json: {
        question: questionText,
        message_type: 'text',
        designer_phone: item.designer_phone || '',
        original_message_id: item.original_message_id || '',
        skip: false
      }
    });
  }
}

// Process voice messages - ONLY use items with transcription
for (const { item: inputItem, hasTranscription } of voiceItems) {
  if (!hasTranscription) {
    // Skip empty voice items from text path
    continue;
  }

  const item = inputItem.json;
  let transcribedText = (item.text || '').trim();

  // Remove RTL markers
  if (transcribedText) {
    transcribedText = transcribedText.replace(/[\u202E\u202D\u202C\u200E\u200F]/g, '').trim();
  }

  if (transcribedText && transcribedText.length > 0) {
    results.push({
      json: {
        question: transcribedText,
        message_type: 'ptt',
        designer_phone: item.designer_phone || '',
        original_message_id: item.original_message_id || '',
        skip: false
      }
    });
  }
}

return results;

